drawLine('M ' + a.right + ' ' + a.cy + ' L ' + midX + ' ' + a.cy + ' L ' + midX + ' ' + next.cy, { active: !!matches['qf_1'].winner });
drawLine('M ' + b.right + ' ' + b.cy + ' L ' + midX + ' ' + b.cy + ' L ' + midX + ' ' + next.cy, { active: !!matches['qf_2'].winner });
